const dataRaw = $input.all()[0].json;
const apiResponse = Array.isArray(dataRaw) ? dataRaw[0] : dataRaw;
const stockData = apiResponse.results[0];

// 2. Extrai apenas os preços ajustados para evitar distorções de dividendos
const prices = stockData.historicalDataPrice.map(item => item.adjustedClose);

// 3. Função auxiliar para calcular tudo com base num número X de dias
function calculateMetrics(closes, daysToCalculate) {
  // Pega apenas os últimos X dias do array
  const recentCloses = closes.slice(-daysToCalculate);
  const actualDays = recentCloses.length;

  if (actualDays < 2) {
    return { erro: "Dias insuficientes para cálculo" };
  }

  // --- VARIAÇÃO PERCENTUAL ---
  const currentPrice = recentCloses[recentCloses.length - 1];
  const oldPrice = recentCloses[0];
  const percentVariation = ((currentPrice - oldPrice) / oldPrice) * 100;

  // --- MÉDIA MÓVEL SIMPLES---
  const sumCloses = recentCloses.reduce((acc, val) => acc + val, 0);
  const sma = sumCloses / actualDays;

  // --- VOLATILIDADE ANUALIZADA ---
  const dailyReturns = [];
  for (let i = 1; i < actualDays; i++) {
    const dayReturn = (recentCloses[i] - recentCloses[i - 1]) / recentCloses[i - 1];
    dailyReturns.push(dayReturn);
  }

  const meanReturn = dailyReturns.reduce((acc, val) => acc + val, 0) / dailyReturns.length;

  let sumSquaredDiffs = 0;
  for (let r of dailyReturns) {
    sumSquaredDiffs += Math.pow(r - meanReturn, 2);
  }

  const variance = sumSquaredDiffs / (dailyReturns.length - 1);
  const standardDeviation = Math.sqrt(variance);

  // Multiplica por raiz de 252 (dias úteis no ano) e por 100 para virar porcentagem
  const annualizedVolatility = standardDeviation * Math.sqrt(252) * 100;

  // Formata os números para ficarem com 2 casas decimais, ideal para salvar em banco ou mandar via msg
  return {
    dias_analisados: actualDays,
    variacao_percentual: Number(percentVariation.toFixed(2)),
    sma: Number(sma.toFixed(2)),
    volatilidade_anualizada_percentual: Number(annualizedVolatility.toFixed(2))
  };
}

// 4. Executa os cálculos para as janelas de tempo desejadas
const metricas7Dias = calculateMetrics(prices, 7);
const metricas30Dias = calculateMetrics(prices, 30);

// 5. Retorna o JSON limpo e formatado para o próximo nó da sua automação
return {
  ativo: stockData.symbol,
  empresa: stockData.longName,
  preco_atual: stockData.regularMarketPrice,
  analise_curto_prazo: metricas7Dias,
  analise_medio_prazo: metricas30Dias,
  logomarca: stockData.logourl
};
